Platform::String^ XamlDiagnosticsTestHelpers::gridString =
L"<Grid x:Name='root' xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml' Background='Red' Projection='{x:Null}' Margin='1,1,2,3' Height='45' Width='45'>"
L"  <Grid.ColumnDefinitions>"
L"      <ColumnDefinition Width='*'/>"
L"      <ColumnDefinition Width='Auto'/>"
L"  </Grid.ColumnDefinitions>"
L"  <Grid.RowDefinitions>"
L"      <RowDefinition Height='*'/>"
L"      <RowDefinition Height='Auto'/>"
L"  </Grid.RowDefinitions>"
L"  <Grid.Resources>"
L"      <Style x:Key='rectangleStyle' TargetType='Rectangle'>"
L"          <Setter Property='Fill' Value='Green' />"
L"      </Style>"
L"  </Grid.Resources>"
L"  <Rectangle x:Name='Verified' Grid.Row='1' Grid.Column='1' Style='{StaticResource rectangleStyle}' Fill='Yellow' Height='30' Width='30' />"
L"  <Grid x:Name='child' Background='Red'>"
L"    <Rectangle x:Name='childVerified' Grid.Row='1' Grid.Column='1' Style='{StaticResource rectangleStyle}' Fill='{Binding ElementName=Verified, Path=Fill}' Height='30' Width='30'  />"
L"  </Grid>"
L"  <TextBox x:Name='texty' Width='Auto' Height='{Binding ElementName=childVerified, Path=Height}' FontFamily='Segoe UI' HorizontalAlignment='{Binding ElementName = FakeElement, Path = Visibility, FallbackValue = Right}'/>"
L"  <Rectangle x:Name='redRect' Fill='Red' />"
L"</Grid>";

