Platform::String^ XamlDiagnosticsTestHelpers::modifiableSetterAndStoryboardString =
L"<Grid xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml' x:Name = 'parent'>\r\n"
L"  <Grid.Resources>\r\n"
L"    <Storyboard x:Name = 'storyboard' x:Key = 'storyboardKey'>\r\n"
L"      <DoubleAnimation EnableDependentAnimation = 'True' From = '110' To = '200' Duration = '00:00:6'\r\n"
L"       Storyboard.TargetName = 'button'\r\n"
L"       Storyboard.TargetProperty = 'Height' />\r\n"
L"    </Storyboard>\r\n"
L"  </Grid.Resources>\r\n"
L"  <Button x:Name = 'button' Height = '100' Width = '100' Background = 'Green' />\r\n"
L"  <VisualStateManager.VisualStateGroups>\r\n"
L"    <VisualStateGroup x:Name = 'visualGroup'>\r\n"
L"      <VisualState x:Name = 'visualState'>\r\n"
L"        <VisualState.StateTriggers>\r\n"
L"          <AdaptiveTrigger MinWindowWidth = '0' />\r\n"
L"        </VisualState.StateTriggers>\r\n"
L"        <VisualState.Setters>\r\n"
L"          <Setter x:Name = 'setter' Target = 'button.Width' Value = '200' />\r\n"
L"        </VisualState.Setters>\r\n"
L"      </VisualState>\r\n"
L"    </VisualStateGroup>\r\n"
L"  </VisualStateManager.VisualStateGroups>\r\n"
L"</Grid>\r\n";

Platform::String^ XamlDiagnosticsTestHelpers::visualStatesAndTriggersString =
L"<Grid xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml' x:Name = 'parent'>\r\n"
L"  <ContentControl x:Name = 'contentControl'>\r\n"
L"    <ContentControl.Template>\r\n"
L"      <ControlTemplate>\r\n"
L"        <StackPanel x:Name = 'visualStateTestParent' Height = '500' Width = '500' Background = 'Blue'>\r\n"
L"          <Button x:Name = 'visualStateTriggerTest' Height = '100' Width = '100' Background = 'Red'></Button>\r\n"
L"          <Button x:Name = 'visualStateManualTest' Height = '100' Width = '100' Background = 'Green'></Button>\r\n"
L"          <VisualStateManager.VisualStateGroups>\r\n"
L"            <VisualStateGroup x:Name = 'group1'>\r\n"
L"              <VisualState x:Name = 'VisualStateTriggerTest'>\r\n"
L"                <VisualState.StateTriggers>\r\n"
L"                  <AdaptiveTrigger MinWindowWidth = '1' />\r\n"
L"                </VisualState.StateTriggers>\r\n"
L"                <Storyboard x:Name = 'myStoryboard'>\r\n"
L"                  <DoubleAnimation EnableDependentAnimation = 'True' From = '110' To = '300' Duration = '00:00:1'\r\n"
L"                  Storyboard.TargetName = 'visualStateTriggerTest'\r\n"
L"                  Storyboard.TargetProperty = 'Height'>\r\n"
L"                    <DoubleAnimation.EasingFunction>\r\n"
L"                      <BounceEase Bounces = '2' EasingMode = 'EaseOut' Bounciness = '2' />\r\n"
L"                    </DoubleAnimation.EasingFunction>\r\n"
L"                  </DoubleAnimation>\r\n"
L"                </Storyboard>\r\n"
L"                <VisualState.Setters>\r\n"
L"                  <Setter Target = 'visualStateTriggerTest.Width' Value = '300' />\r\n"
L"                </VisualState.Setters>\r\n"
L"              </VisualState>\r\n"
L"            </VisualStateGroup>\r\n"
L"            <VisualStateGroup x:Name = 'group2'>\r\n"
L"              <VisualState x:Name = 'VisualStateSetterStoryboard'>\r\n"
L"                <Storyboard x:Name = 'myStoryboard2'>\r\n"
L"                  <DoubleAnimation EnableDependentAnimation = 'True' From = '110' To = '300' Duration = '00:00:1'\r\n"
L"                  Storyboard.TargetName = 'visualStateManualTest'\r\n"
L"                  Storyboard.TargetProperty = 'Height'>\r\n"
L"                    <DoubleAnimation.EasingFunction>\r\n"
L"                      <BounceEase Bounces = '2' EasingMode = 'EaseOut' Bounciness = '2' />\r\n"
L"                    </DoubleAnimation.EasingFunction>\r\n"
L"                  </DoubleAnimation>\r\n"
L"                </Storyboard>\r\n"
L"                <VisualState.Setters>\r\n"
L"                  <Setter Target = 'visualStateManualTest.Width' Value = '300' />\r\n"
L"                </VisualState.Setters>\r\n"
L"              </VisualState>\r\n"
L"            </VisualStateGroup>\r\n"
L"            <VisualStateGroup x:Name = 'group3'>\r\n"
L"              <VisualState x:Name = 'VisualStateOverlap'>\r\n"
L"                <VisualState.Setters>\r\n"
L"                  <Setter Target = 'visualStateManualTest.Width' Value = '330' />\r\n"
L"                </VisualState.Setters>\r\n"
L"              </VisualState>\r\n"
L"            </VisualStateGroup>\r\n"
L"          </VisualStateManager.VisualStateGroups>\r\n"
L"        </StackPanel>\r\n"
L"      </ControlTemplate>\r\n"
L"    </ContentControl.Template>\r\n"
L"  </ContentControl>\r\n"
L"</Grid>\r\n";

Platform::String^ XamlDiagnosticsTestHelpers::stackPanelWithButtonString =
L"<StackPanel x:Name='MyPanel' xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml' Background='Red' Width='45' Height='45'>"
L"  <Button x:Name='MyButton' Content='Click'>"
L"    <Button.RenderTransform>"
L"      <CompositeTransform ScaleX='3'/>"
L"    </Button.RenderTransform>"
L"  </Button>"
L"</StackPanel>";

Platform::String^ XamlDiagnosticsTestHelpers::stackPanelWithNestedStylesString =
L"<StackPanel x:Name='panel' xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' xmlns:x='http://schemas.microsoft.com/winfx/2006/xaml' Background='Red' Width='45' Height='45'>\r\n"
L"  <StackPanel.Resources>\r\n"
L"    <Style x:Key='unusedStyle' TargetType='Button'>\r\n"
L"      <Setter Property='Background' Value='Yellow' />\r\n"
L"      <Setter Property='Foreground' Value='Purple' />\r\n"
L"    </Style>\r\n"
L"    <Style x:Key='style1' TargetType='Button'>\r\n"
L"      <Setter Property='Background' Value='Blue' />\r\n"
L"      <Setter Property='Foreground' Value='White' />\r\n"
L"    </Style>\r\n"
L"    <Style x:Key='style2' TargetType='Button' BasedOn='{StaticResource style1}'>\r\n"
L"      <Setter Property='Background' Value='Red' />\r\n"
L"    </Style>\r\n"
L"    <Style x:Key='style3' TargetType='Button' BasedOn='{StaticResource style2}'>\r\n"
L"      <Setter Property='Width' Value='60' />\r\n"
L"    </Style>\r\n"
L"  </StackPanel.Resources>"
L"  <Button x:Name='button' Content='Click' Style='{StaticResource style3}'/>"
L"</StackPanel>";